Suggestion for a workaround in the meantime:

```
from itertools import zip_longest

def grouper(iterable, n, fillvalue=None):
	"Collect data into fixed-length chunks or blocks"
	# grouper('ABCDEFG', 3, 'x') --> ABC DEF Gxx"
	args = [iter(iterable)] * n
	return zip_longest(*args, fillvalue=fillvalue)

def streaming_bulk(client, actions, chunk_size=500, max_chunk_bytes=100*1024*1024, raise_on_error=True, expand_action_callback=expand_action, raise_on_exception=True, **kwargs):
	actions = map(expand_action_callback, actions)

	for bulk_actions in _chunk_actions(actions, chunk_size, max_chunk_bytes, client.transport.serializer):
		try:
			yield from _process_bulk_chunk(client, bulk_actions, **kwargs)
		except UnicodeEncodeError:
			# Do individual loading
			for action, doc in grouper(bulk_actions, 2):
				action = json.loads(action)
				doc = json.loads(doc)
				try:
					client.index(action['index']['_index'], action['index']['_type'], doc, action['index']['_id'])
				except UnicodeEncodeError:
					pass
```

